function setBackgroundBlur(targetId,scrollDivisor=300,disableBlur=!1,isMenuBlur=!1){if(!targetId){console.error("data-blur-id is null");return}const blurElement=document.getElementById(targetId);if(!blurElement)return;disableBlur?(blurElement.setAttribute("aria-hidden","true"),isMenuBlur?blurElement.style.display="":(blurElement.style.display="none",blurElement.style.opacity="0")):(blurElement.style.display="",blurElement.removeAttribute("aria-hidden"));const updateBlur=()=>{if(!disableBlur||isMenuBlur){const scroll=window.pageYOffset||document.documentElement.scrollTop||document.body.scrollTop||0;blurElement.style.opacity=scroll/scrollDivisor}};blurElement.setAttribute("role","presentation"),blurElement.setAttribute("tabindex","-1"),window.addEventListener("scroll",updateBlur),updateBlur()}document.querySelectorAll("script[data-blur-id]").forEach(script=>{const targetId=script.getAttribute("data-blur-id"),scrollDivisor=Number(script.getAttribute("data-scroll-divisor")||300),isMenuBlur=targetId==="menu-blur",settings=JSON.parse(localStorage.getItem("a11ySettings")||"{}"),disableBlur=settings.disableBlur;setBackgroundBlur(targetId,scrollDivisor,disableBlur,isMenuBlur)})